 99 struct FactOrCheck {
100   enum class EntryTy {
101     ConditionFact, /// A condition that holds on entry to a block.
102     InstFact,      /// A fact that holds after Inst executed (e.g. an assume or
103                    /// min/mix intrinsic.
104     InstCheck,     /// An instruction to simplify (e.g. an overflow math
105                    /// intrinsics).
106     UseCheck       /// An use of a compare instruction to simplify.
107   };
108 
109   union {
110     Instruction *Inst;
111     Use *U;
112     ConditionTy Cond;
113   };
114 
115   /// A pre-condition that must hold for the current fact to be added to the
116   /// system.
117   ConditionTy DoesHold;
118 
119   unsigned NumIn;
120   unsigned NumOut;
121   EntryTy Ty;
122 
123   FactOrCheck(EntryTy Ty, DomTreeNode *DTN, Instruction *Inst)
124       : Inst(Inst), NumIn(DTN->getDFSNumIn()), NumOut(DTN->getDFSNumOut()),
125         Ty(Ty) {}
126 
127   FactOrCheck(DomTreeNode *DTN, Use *U)
128       : U(U), NumIn(DTN->getDFSNumIn()), NumOut(DTN->getDFSNumOut()),
129         Ty(EntryTy::UseCheck) {}
130 
131   FactOrCheck(DomTreeNode *DTN, CmpPredicate Pred, Value *Op0, Value *Op1,
132               ConditionTy Precond = {})
133       : Cond(Pred, Op0, Op1), DoesHold(Precond), NumIn(DTN->getDFSNumIn()),
134         NumOut(DTN->getDFSNumOut()), Ty(EntryTy::ConditionFact) {}
135 
136   static FactOrCheck getConditionFact(DomTreeNode *DTN, CmpPredicate Pred,
137                                       Value *Op0, Value *Op1,
138                                       ConditionTy Precond = {}) {
139     return FactOrCheck(DTN, Pred, Op0, Op1, Precond);
140   }
141 
142   static FactOrCheck getInstFact(DomTreeNode *DTN, Instruction *Inst) {
143     return FactOrCheck(EntryTy::InstFact, DTN, Inst);
144   }
