147     return FactOrCheck(DTN, U);
148   }
149 
150   static FactOrCheck getCheck(DomTreeNode *DTN, CallInst *CI) {
151     return FactOrCheck(EntryTy::InstCheck, DTN, CI);
152   }
153 
154   bool isCheck() const {
155     return Ty == EntryTy::InstCheck || Ty == EntryTy::UseCheck;
156   }
157 
158   Instruction *getContextInst() const {
159     assert(!isConditionFact());
160     if (Ty == EntryTy::UseCheck)
161       return getContextInstForUse(*U);
162     return Inst;
