1139 void State::addConstantRangeFact(Value *V, DomTreeNode *DTN) {
1140   if (!RangeFactsComputed.insert(V).second)
1141     return;
1142   Type *Ty = V->getType();
1143   if (!Ty->isIntegerTy() || Ty->getIntegerBitWidth() > 64)
1144     return;
1145 
1146   ConstantRange CR =
1147       computeConstantRange(V, /*ForSigned=*/false, /*UseInstrInfo=*/true);
1148   if (CR.isFullSet() || CR.isEmptySet())
1149     return;
1150 
1151   APInt UMin = CR.getUnsignedMin();
1152   APInt UMax = CR.getUnsignedMax();
1153   if (!UMin.isZero())
1154     WorkList.push_back(FactOrCheck::getConditionFact(
1155         DTN, CmpInst::ICMP_UGE, V, ConstantInt::get(Ty, UMin)));
1156   if (!UMax.isAllOnes())
1157     WorkList.push_back(FactOrCheck::getConditionFact(
1158         DTN, CmpInst::ICMP_ULE, V, ConstantInt::get(Ty, UMax)));
1159 }
