1250       break;
1251     // Enqueue the intrinsics to add extra info.
1252     case Intrinsic::umin:
1253     case Intrinsic::umax:
1254     case Intrinsic::smin:
1255     case Intrinsic::smax:
1256       // TODO: handle llvm.abs as well
1257       WorkList.push_back(
1258           FactOrCheck::getCheck(DT.getNode(&BB), cast<CallInst>(&I)));
1259       [[fallthrough]];
1260     case Intrinsic::uadd_sat:
1261     case Intrinsic::usub_sat:
1262       // TODO: Check if it is possible to instead only added the min/max facts
1263       // when simplifying uses of the min/max intrinsics.
1264       if (!isGuaranteedNotToBePoison(&I))
1265         break;
1266       [[fallthrough]];
1267     case Intrinsic::abs:
1268       WorkList.push_back(FactOrCheck::getInstFact(DT.getNode(&BB), &I));
1269       break;
1270     }
1271 
1272     // Add facts from unsigned division and remainder.
1273     //   urem x, n: result < n  and  result <= x
1274     //   udiv x, n: result <= x
1275     if (auto *BO = dyn_cast<BinaryOperator>(&I)) {
1276       if ((BO->getOpcode() == Instruction::URem ||
1277            BO->getOpcode() == Instruction::UDiv) &&
1278           isGuaranteedNotToBePoison(BO))
1279         WorkList.push_back(FactOrCheck::getInstFact(DT.getNode(&BB), BO));
1280     }
1281 
1282     GuaranteedToExecute &= isGuaranteedToTransferExecutionToSuccessor(&I);
1283   }
1284 
1285   if (auto *Switch = dyn_cast<SwitchInst>(BB.getTerminator())) {
1286     for (auto &Case : Switch->cases()) {
1287       BasicBlock *Succ = Case.getCaseSuccessor();
1288       Value *V = Case.getCaseValue();
1289       if (!canAddSuccessor(BB, Succ))
1290         continue;
1291       WorkList.emplace_back(FactOrCheck::getConditionFact(
1292           DT.getNode(Succ), CmpInst::ICMP_EQ, Switch->getCondition(), V));
1293     }
1294     return;
1295   }
1296 
1297   auto *Br = dyn_cast<BranchInst>(BB.getTerminator());
1298   if (!Br || !Br->isConditional())
1299     return;
1300 
1301   Value *Cond = Br->getCondition();
1302 
1303   // If the condition is a chain of ORs/AND and the successor only has the
1304   // current block as predecessor, queue conditions for the successor.
1305   Value *Op0, *Op1;
1306   if (match(Cond, m_LogicalOr(m_Value(Op0), m_Value(Op1))) ||
1307       match(Cond, m_LogicalAnd(m_Value(Op0), m_Value(Op1)))) {
1308     bool IsOr = match(Cond, m_LogicalOr());
1309     bool IsAnd = match(Cond, m_LogicalAnd());
1310     // If there's a select that matches both AND and OR, we need to commit to
1311     // one of the options. Arbitrarily pick OR.
1312     if (IsOr && IsAnd)
1313       IsAnd = false;
1314 
1315     BasicBlock *Successor = Br->getSuccessor(IsOr ? 1 : 0);
1316     if (canAddSuccessor(BB, Successor)) {
1317       SmallVector<Value *> CondWorkList;
1318       SmallPtrSet<Value *, 8> SeenCond;
1319       auto QueueValue = [&CondWorkList, &SeenCond](Value *V) {
1320         if (SeenCond.insert(V).second)
1321           CondWorkList.push_back(V);
1322       };
1323       QueueValue(Op1);
1324       QueueValue(Op0);
1325       while (!CondWorkList.empty()) {
1326         Value *Cur = CondWorkList.pop_back_val();
1327         if (auto *Cmp = dyn_cast<ICmpInst>(Cur)) {
1328           WorkList.emplace_back(FactOrCheck::getConditionFact(
1329               DT.getNode(Successor),
1330               IsOr ? Cmp->getInverseCmpPredicate() : Cmp->getCmpPredicate(),
1331               Cmp->getOperand(0), Cmp->getOperand(1)));
1332           continue;
1333         }
1334         if (IsOr && match(Cur, m_LogicalOr(m_Value(Op0), m_Value(Op1)))) {
1335           QueueValue(Op1);
1336           QueueValue(Op0);
1337           continue;
1338         }
1339         if (IsAnd && match(Cur, m_LogicalAnd(m_Value(Op0), m_Value(Op1)))) {
1340           QueueValue(Op1);
1341           QueueValue(Op0);
1342           continue;
1343         }
1344       }
1345     }
1346     return;
1347   }
1348 
1349   auto *CmpI = dyn_cast<ICmpInst>(Br->getCondition());
1350   if (!CmpI)
1351     return;
1352   if (canAddSuccessor(BB, Br->getSuccessor(0)))
1353     WorkList.emplace_back(FactOrCheck::getConditionFact(
1354         DT.getNode(Br->getSuccessor(0)), CmpI->getCmpPredicate(),
1355         CmpI->getOperand(0), CmpI->getOperand(1)));
1356   if (canAddSuccessor(BB, Br->getSuccessor(1)))
1357     WorkList.emplace_back(FactOrCheck::getConditionFact(
1358         DT.getNode(Br->getSuccessor(1)), CmpI->getInverseCmpPredicate(),
1359         CmpI->getOperand(0), CmpI->getOperand(1)));
